LogicListener = {}
LogicListener.goldAppleTimeId = {}
LogicListener.goldAppleAddHpTimeId = {}
LogicListener.goldAppleFreshTimeId = {}
LogicListener.blockAirCache = {}

function LogicListener:init()
    ItemSkillAttackEvent.registerCallBack(self.onItemSkillAttack)
    ItemSkillConsumptionItemEvent.registerCallBack(self.onItemSkillConsumptionItem)
    EntityItemSpawnEvent.registerCallBack(self.onEntityItemSpawn)
    UseItemBucketEvent.registerCallBack(self.onUseItemBucket)
    FoodEatenEvent.registerCallBack(self.onFoodEaten)
    ToolDurableEvent.registerCallBack(self.onToolDurable)
    EntityLivingBaseFallNoNeedCalBlockIdEvent.registerCallBack(self.onEntityLivingBaseFallNoNeedCalBlockId)
    UseItemBucketInBlockEvent.registerCallBack(self.onUseItemBucketInBlock)
end

function LogicListener.onEntityItemSpawn(itemId, itemMeta, behavior, discard)
    if behavior == "player.drop" then
        return ItemHelper:canSpawnEntity(itemId)
    end
    return true
end

function LogicListener.onItemSkillAttack(entityId, itemId, position, itemEntityId)
    local player = PlayerManager:getPlayerByEntityId(entityId)
    if player == nil then
        return
    end

    if player.isLife == false then
        return
    end
    local skill = SkillConfig:getSkill(itemId)
    if skill ~= nil then
        GameSkill.new(skill, player, position, itemEntityId)
    end
end

function LogicListener.onItemSkillConsumptionItem(rakssid, itemId)
    local player = PlayerManager:getPlayerByRakssid(rakssid)
    if player == nil then
        return
    end

    if itemId == ItemID.ENDER_PEARL or itemId == ItemID.FLARE_BOMB or itemId == ItemID.HAND_GRENADE
            or itemId == ItemID.WitchPotion or itemId == ItemID.SnowBallInsect then
        player:removeItem(itemId, 1)
        if itemId == ItemID.FLARE_BOMB then
            GamePacketSender:broadcastSound(SoundConfig.shootFire, player:getPosition())
        end
    end
end

function LogicListener.onUseItemBucket(entityId, itemId)
    local player = PlayerManager:getPlayerByEntityId(entityId)
    if player == nil then
        return true
    end

    if ItemID.BUCKET_WATER == itemId
            or ItemID.BUCKET_MILK == itemId
            or ItemID.POTION_INVISIBILITY == itemId
            or ItemID.POTION_JUMP == itemId
            or ItemID.POTION_MOVESPEED == itemId then
        return false
    end

    return true
end

function LogicListener.onFoodEaten(entityId, itemId)
    local player = PlayerManager:getPlayerByEntityId(entityId)
    if player == nil then
        return true
    end

    if ItemID.GOLD_APPLE == itemId then

        player:resetApple()
        player.entityPlayerMP:appleFresh(-1)

        local hash = tostring(tostring(player.rakssid) .. os.time())
        -- add hp
        local hpCountDown = tonumber(GameConfig.goldApple[1].hpCountDown)
        local armorDuration = tonumber(GameConfig.goldApple[1].armorDuration)
        local armoraddDuration = tonumber(GameConfig.goldApple[1].armoraddDuration)

        LogicListener.goldAppleAddHpTimeId[hash] = LuaTimer:scheduleTimer(function()
            if not player.banCureBuff then
                player:addHealth(tonumber(GameConfig.goldApple[1].addHpValue))
            end

        end, hpCountDown * 1000, armorDuration / hpCountDown)

        -- add apple

        player.maxApple = tonumber(GameConfig.goldApple[1].addarmor)
        player.curApple = tonumber(GameConfig.goldApple[1].addarmor)
        player:updateApple()

        LogicListener.goldAppleTimeId[hash] = LuaTimer:schedule(function()

            if player.entityPlayerMP ~= nil then
                player.entityPlayerMP:changeApple(0, 0)
                player.curApple = 0
                player.maxApple = 0
            end

            if LogicListener.goldAppleTimeId[hash] ~= nil then
                LuaTimer:cancel(LogicListener.goldAppleTimeId[hash])
                LogicListener.goldAppleTimeId[hash] = nil
            end

        end, armoraddDuration * 1000, nil)

        local freshTime = armoraddDuration - 3
        -- HostApi.log("freshTime " .. freshTime)
        if freshTime > 0 then
            LogicListener.goldAppleFreshTimeId[hash] = LuaTimer:schedule(function()

                if player.entityPlayerMP ~= nil then
                    -- HostApi.log("appleFresh")
                    player.entityPlayerMP:appleFresh(3)
                end

                if LogicListener.goldAppleFreshTimeId[hash] ~= nil then
                    LuaTimer:cancel(LogicListener.goldAppleFreshTimeId[hash])
                    LogicListener.goldAppleFreshTimeId[hash] = nil
                end

            end, freshTime * 1000, nil)
        end

        -- player:addEffect(6, armorDuration, 0)

        return false
    end

    return true
end

function LogicListener.onToolDurable(itemId, itemDamage)
    return false
end

function LogicListener.onEntityLivingBaseFallNoNeedCalBlockId(entityId)
    local player = PlayerManager:getPlayerByEntityId(entityId)
    if player == nil then
        return true
    end

    return false
end

function LogicListener.onUseItemBucketInBlock(entityId, itemId, vec3i)
    local player = PlayerManager:getPlayerByEntityId(entityId)
    if player == nil then
        return false
    end

    if itemId == ItemID.BUCKET_WATER then
        local localVec3i = vec3i
        localVec3i.y = localVec3i.y + 1
        local isInArea = TeamConfig:isInTeamArea(localVec3i)
        if isInArea == true then
            MessagesManage:sendSystemTipsToPlayer(player.rakssid, Messages:msgBlockPlaceTip())
            if LogicListener.blockAirCache[VectorUtil.hashVector3(vec3i)] == nil then
                EngineWorld:setBlock(vec3i, 0, 1, 3, true)
                LogicListener.blockAirCache[VectorUtil.hashVector3(vec3i)] = true
            else
                EngineWorld:setBlock(vec3i, 0, 0, 3, true)
                LogicListener.blockAirCache[VectorUtil.hashVector3(vec3i)] = nil
            end

            return false
        end
    end

    return true
end

return LogicListener